import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const [positions, setPositions] = useState([]);
  const containerRef = useRef(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  const allSkills = [
    // Frontend
    { name: 'HTML5', icon: '🌐', category: 'Frontend' },
    { name: 'CSS3', icon: '🎨', category: 'Frontend' },
    { name: 'JavaScript', icon: '⚡', category: 'Frontend' },
    { name: 'TypeScript', icon: '📘', category: 'Frontend' },
    { name: 'React', icon: '⚛️', category: 'Frontend' },
    { name: 'Next.js', icon: '▲', category: 'Frontend' },
    { name: 'Tailwind CSS', icon: '💨', category: 'Frontend' },
    { name: 'Redux', icon: '🔄', category: 'Frontend' },
    { name: 'Framer Motion', icon: '🎬', category: 'Frontend' },
    // Backend
    { name: 'Node.js', icon: '🟢', category: 'Backend' },
    { name: 'Express.js', icon: '🚀', category: 'Backend' },
    { name: 'MongoDB', icon: '🍃', category: 'Backend' },
    { name: 'MySQL', icon: '🐬', category: 'Backend' },
    { name: 'PostgreSQL', icon: '🐘', category: 'Backend' },
    { name: 'Firebase', icon: '🔥', category: 'Backend' },
    { name: 'JWT', icon: '🔐', category: 'Backend' },
    { name: 'REST API', icon: '🔗', category: 'Backend' },
    { name: 'Socket.io', icon: '📡', category: 'Backend' },
    // Programming Languages
    { name: 'Java', icon: '☕', category: 'Languages' },
    { name: 'Python', icon: '🐍', category: 'Languages' },
    { name: 'C++', icon: '⚙️', category: 'Languages' },
    { name: 'C', icon: '🔧', category: 'Languages' },
    { name: 'C#', icon: '🎯', category: 'Languages' },
    { name: 'PHP', icon: '🐘', category: 'Languages' },
    // Tools
    { name: 'Git', icon: '🔀', category: 'Tools' },
    { name: 'GitHub', icon: '🐙', category: 'Tools' },
    { name: 'Docker', icon: '🐳', category: 'Tools' },
    { name: 'Linux', icon: '🐧', category: 'Tools' },
    { name: 'VS Code', icon: '💻', category: 'Tools' },
    { name: 'Postman', icon: '📮', category: 'Tools' },
    { name: 'Figma', icon: '🎯', category: 'Tools' }
  ];

  // Skill sizes
  const getSkillSize = (index) => {
    const sizes = [62, 58, 65, 55, 60, 68, 52, 70, 56];
    return sizes[index % sizes.length];
  };

  // Check overlap between two positions
  const isOverlapping = (pos1, pos2, minDistance) => {
    const dx = pos1.x - pos2.x;
    const dy = pos1.y - pos2.y;
    return (dx * dx + dy * dy) < (minDistance * minDistance);
  };

  // Generate non-overlapping positions
  const generatePositions = (count, width, height) => {
    const positions = [];
    const minDistance = 95;
    const padding = 10;
    const maxAttempts = 3000;

    for (let i = 0; i < count; i++) {
      let attempts = 0;
      let pos;
      let found = false;

      while (!found && attempts < maxAttempts) {
        pos = {
          x: padding + Math.random() * (width - padding * 2),
          y: padding + Math.random() * (height - padding * 2),
          targetX: padding + Math.random() * (width - padding * 2),
          targetY: padding + Math.random() * (height - padding * 2),
          rotation: Math.random() * 360,
          scale: 0.8 + Math.random() * 0.4,
          duration: 1 + Math.random() * 0.5,
          delay: Math.random() * 0.3,
          size: getSkillSize(i)
        };

        let overlapping = false;
        for (const existing of positions) {
          if (isOverlapping(pos, existing, minDistance)) {
            overlapping = true;
            break;
          }
        }

        if (!overlapping) {
          found = true;
        }
        attempts++;
      }

      if (found) {
        positions.push(pos);
      } else {
        positions.push({
          x: padding + Math.random() * (width - padding * 2),
          y: padding + Math.random() * (height - padding * 2),
          targetX: padding + Math.random() * (width - padding * 2),
          targetY: padding + Math.random() * (height - padding * 2),
          rotation: Math.random() * 360,
          scale: 0.8 + Math.random() * 0.4,
          duration: 1 + Math.random() * 0.5,
          delay: Math.random() * 0.3,
          size: getSkillSize(i)
        });
      }
    }

    return positions;
  };

  // Update container dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        setDimensions({ width: rect.width, height: rect.height });
      }
    };

    updateDimensions();
    window.addEventListener('resize', updateDimensions);

    return () => window.removeEventListener('resize', updateDimensions);
  }, []);

  // Initialize positions
  useEffect(() => {
    if (dimensions.width > 0 && dimensions.height > 0) {
      const newPositions = generatePositions(allSkills.length, dimensions.width, dimensions.height);
      setPositions(newPositions);
    }
  }, [dimensions]);

  // Move to new positions every 1 second
  useEffect(() => {
    if (positions.length === 0 || dimensions.width === 0) return;

    const interval = setInterval(() => {
      setPositions(prev => {
        const padding = 10;
        const w = dimensions.width;
        const h = dimensions.height;

        // Generate new targets with collision avoidance
        const newTargets = [];
        const minDistance = 95;

        for (let i = 0; i < prev.length; i++) {
          let attempts = 0;
          let targetX, targetY;
          let found = false;

          while (!found && attempts < 100) {
            targetX = padding + Math.random() * (w - padding * 2);
            targetY = padding + Math.random() * (h - padding * 2);

            let overlapping = false;
            for (let j = 0; j < newTargets.length; j++) {
              const dx = targetX - newTargets[j].x;
              const dy = targetY - newTargets[j].y;
              if ((dx * dx + dy * dy) < (minDistance * minDistance)) {
                overlapping = true;
                break;
              }
            }

            if (!overlapping) {
              found = true;
            }
            attempts++;
          }

          newTargets.push({
            x: targetX || padding + Math.random() * (w - padding * 2),
            y: targetY || padding + Math.random() * (h - padding * 2)
          });
        }

        return prev.map((pos, index) => ({
          ...pos,
          targetX: newTargets[index].x,
          targetY: newTargets[index].y,
          rotation: pos.rotation + (Math.random() - 0.5) * 20,
          duration: 0.8 + Math.random() * 0.4,
          delay: Math.random() * 0.2
        }));
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [positions.length, dimensions]);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          ref={containerRef}
          className="relative min-h-[650px] w-full overflow-hidden rounded-3xl bg-gradient-to-br from-[#0a0a0f] via-[#0d0d1a] to-[#0a0a0f] border border-purple-500/10"
          style={{
            boxShadow: 'inset 0 0 100px rgba(139,92,246,0.03)'
          }}
        >
          {/* Background Glow */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="w-[600px] h-[600px] rounded-full bg-purple-500/5 blur-3xl"></div>
            <div className="absolute w-[400px] h-[400px] rounded-full bg-purple-400/3 blur-3xl"></div>
          </div>

          {/* Floating Particles Background */}
          <div className="absolute inset-0 pointer-events-none">
            {[...Array(30)].map((_, i) => (
              <div
                key={`particle-${i}`}
                className="absolute rounded-full bg-purple-400/10"
                style={{
                  width: 2 + Math.random() * 4,
                  height: 2 + Math.random() * 4,
                  top: `${Math.random() * 100}%`,
                  left: `${Math.random() * 100}%`,
                  animation: `floatParticle ${10 + Math.random() * 20}s linear infinite`,
                  animationDelay: `${Math.random() * 10}s`
                }}
              />
            ))}
          </div>

          {/* Skills */}
          {positions.map((pos, index) => {
            const skill = allSkills[index];
            if (!skill) return null;

            const isHovered = hoveredSkill === skill.name;

            return (
              <motion.div
                key={skill.name}
                className="absolute cursor-pointer"
                style={{
                  left: `${pos.x}%`,
                  top: `${pos.y}%`,
                  x: '-50%',
                  y: '-50%',
                  zIndex: isHovered ? 50 : 10
                }}
                animate={{
                  x: ['-50%', '-50%'],
                  y: ['-50%', '-50%'],
                  left: [`${pos.x}%`, `${pos.targetX}%`],
                  top: [`${pos.y}%`, `${pos.targetY}%`],
                  rotate: [pos.rotation, pos.rotation + 10],
                  scale: isHovered ? 1.25 : pos.scale
                }}
                transition={{
                  left: { duration: pos.duration, ease: 'easeInOut', delay: pos.delay },
                  top: { duration: pos.duration, ease: 'easeInOut', delay: pos.delay },
                  rotate: { duration: pos.duration + 0.5, ease: 'linear' },
                  scale: { duration: 0.3, ease: 'easeOut' }
                }}
                onMouseEnter={() => setHoveredSkill(skill.name)}
                onMouseLeave={() => setHoveredSkill(null)}
                whileHover={{
                  scale: 1.25,
                  transition: { duration: 0.3 }
                }}
              >
                <div
                  className="flex flex-col items-center justify-center rounded-full backdrop-blur-sm transition-all duration-300"
                  style={{
                    width: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                    height: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                    boxShadow: isHovered
                      ? '0 0 60px rgba(139,92,246,0.4), 0 0 120px rgba(139,92,246,0.15)'
                      : '0 0 30px rgba(139,92,246,0.05)',
                    background: isHovered
                      ? 'rgba(26,31,46,0.95)'
                      : 'rgba(26,31,46,0.35)',
                    border: isHovered
                      ? '1.5px solid rgba(139,92,246,0.6)'
                      : '1px solid rgba(255,255,255,0.05)',
                    transform: isHovered ? 'scale(1.1)' : 'scale(1)'
                  }}
                >
                  <span
                    className="transition-all duration-300"
                    style={{
                      fontSize: isHovered ? '28px' : '20px',
                      filter: isHovered ? 'brightness(1.3) drop-shadow(0 0 20px rgba(139,92,246,0.3))' : 'brightness(0.8)'
                    }}
                  >
                    {skill.icon}
                  </span>

                  {isHovered && (
                    <motion.span
                      className="text-[9px] font-semibold text-white mt-0.5"
                      initial={{ opacity: 0, scale: 0.8 }}
                      animate={{ opacity: 1, scale: 1 }}
                      transition={{ duration: 0.2 }}
                    >
                      {skill.name}
                    </motion.span>
                  )}
                </div>
              </motion.div>
            );
          })}

          {/* Category Labels */}
          <div className="absolute bottom-4 left-4 right-4 flex justify-center gap-6 flex-wrap pointer-events-none">
            {['Frontend', 'Backend', 'Languages', 'Tools'].map((category) => (
              <span
                key={category}
                className="text-[8px] uppercase tracking-widest text-purple-500/30 font-medium"
              >
                {category}
              </span>
            ))}
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white"></div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white"></div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">200</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>

        <div className="text-center text-gray-500 text-xs mt-4 opacity-60">
          Hover on any skill to see more ✨
        </div>
      </div>

      <style>{`
        @keyframes floatParticle {
          0% {
            transform: translateY(1px) translateX(3px);
            opacity: 0;
          }
          10% {
            opacity: 1;
          }
          90% {
            opacity: 1;
          }
          100% {
            transform: translateY(-100px) translateX(${Math.random() * 50 - 25}px);
            opacity: 0;
          }
        }

        .glass-card {
          background: rgba(17, 17, 17, 0.6);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.05);
          transition: all 0.3s ease;
        }

        .glass-card:hover {
          border-color: rgba(139, 92, 246, 0.2);
        }
      `}</style>
    </section>
  );
};

export default Skills;
